from pathlib import Path
import openpyxl
import re
from datetime import datetime, date

COLS = {
    'date':        0,
    'shipment':    1,
    'origin':      2,
    'pallets':     3,
    'exp_cases':   4,
    'temp1':       5,
    'temp2':       6,
    'temp3':       7,
    'warmest':     8,
    'tier':        9,
    'actual':      10,
    'variance':    11,
    'var_pct':     12,
    'damage':      13,
    'disposition': 14,
    'status':      15,
    'notes':       16,
}

def verify(workspace_path, external_services_path=None):
    xlsx_files = list(Path(workspace_path).glob('*.xlsx'))
    if not xlsx_files:
        return {'pass': False, 'score': 0.0, 'feedback': 'No xlsx file found in workspace'}

    def norm(c):
        if c is None:
            return ''
        if isinstance(c, (datetime, date)):
            return str(c.date() if isinstance(c, datetime) else c)
        s = str(c).strip().lower()
        for ch in ('\u2212', '\u2013', '\u2014'):
            s = s.replace(ch, '-')
        s = re.sub(r'[^\w\s.\-]', '', s)
        s = re.sub(r'\s+', ' ', s).strip()
        return s

    best_result = None

    for xlsx_file in xlsx_files:
        try:
            wb = openpyxl.load_workbook(xlsx_file, data_only=True)
        except Exception:
            continue

        for sheet_name in wb.sheetnames:
            ws = wb[sheet_name]
            rows = list(ws.iter_rows(values_only=True))

            candidate_rows = []
            if len(rows) >= 17:
                candidate_rows.append((16, rows[16]))
            for idx, r in enumerate(rows):
                if idx == 16:
                    continue
                r_str = ' '.join([str(x) for x in r if x is not None]).lower()
                if '2026-04-02-001' in r_str or ('waco' in r_str and '2026-04-02' in r_str):
                    candidate_rows.append((idx, r))

            if not candidate_rows:
                result = {'pass': False, 'score': 0.0, 'feedback': f'{xlsx_file.name}/{sheet_name}: no row found for this shipment'}
                if best_result is None or result['score'] > best_result['score']:
                    best_result = result
                continue

            for row_idx, row in candidate_rows:
                row = list(row) + [''] * max(0, 17 - len(row))

                def ceq(col, *targets):
                    return norm(row[col]) in [norm(t) for t in targets]

                def csub(col, target):
                    return norm(target) in norm(row[col])

                checks = {
                    'date 2026-04-02':          (COLS['date'],        csub(COLS['date'],        '2026-04-02'),                                                                    '2026-04-02'),
                    'shipment 2026-04-02-001':  (COLS['shipment'],    csub(COLS['shipment'],    '2026-04-02-001'),                                                                '2026-04-02-001'),
                    'waco transfer':            (COLS['origin'],      ceq(COLS['origin'],      'waco transfer'),                                                                          'Waco Transfer'),
                    'pallets 20':               (COLS['pallets'],     ceq(COLS['pallets'],      '20', '20.0'),                                                                    '20'),
                    'expected cases 400':       (COLS['exp_cases'],   ceq(COLS['exp_cases'],    '400', '400.0'),                                                                  '400'),
                    'temp 1 -9':                (COLS['temp1'],       ceq(COLS['temp1'],        '-9', '-9.0'),                                                                    '-9'),
                    'temp 2 -10':               (COLS['temp2'],       ceq(COLS['temp2'],        '-10', '-10.0'),                                                                  '-10'),
                    'temp 3 -13':               (COLS['temp3'],       ceq(COLS['temp3'],        '-13', '-13.0'),                                                                  '-13'),
                    'warmest -9':               (COLS['warmest'],     ceq(COLS['warmest'],      '-9', '-9.0'),                                                                    '-9'),
                    'tier 2':                   (COLS['tier'],        ceq(COLS['tier'],        'tier 2'),                                                                        'Tier 2'),
                    'actual 399':               (COLS['actual'],      ceq(COLS['actual'],       '399', '399.0'),                                                                  '399'),
                    'variance -1':              (COLS['variance'],    ceq(COLS['variance'],     '-1', '-1.0'),                                                                    '-1'),
                    'variance % -0.25':         (COLS['var_pct'],     csub(COLS['var_pct'],     '-0.25'),                                                                         '-0.25'),
                    'damage note':              (COLS['damage'],      ceq(COLS['damage'],     'One case label torn (SC-001 pallet 3). No breach.'),     'One case label torn (SC-001 pallet 3). No breach.'),
                    'disposition':              (COLS['disposition'], ceq(COLS['disposition'], 'Accept with Note'),                                  'Accept with Note'),
                    'status':                   (COLS['status'],      csub(COLS['status'],      'pending variance resolution'),                                  'Pending Variance Resolution'),
                    'notes warm side':          (COLS['notes'],       csub(COLS['notes'],       'warm side of acceptable range'),                                                 'warm side of acceptable range'),
                    'notes class 1 damage':     (COLS['notes'],       csub(COLS['notes'],       'class 1 damage'),                                                                'class 1 damage'),
                    'notes minor variance':     (COLS['notes'],       csub(COLS['notes'],       'minor variance'),                                                                'minor variance'),
                }

                failed_lines = [
                    f'  {k}: expected "{expected}" | found "{row[col]}"'
                    for k, (col, passed, expected) in checks.items() if not passed
                ]
                score = (len(checks) - len(failed_lines)) / len(checks)

                if not failed_lines:
                    return {
                        'pass': True,
                        'score': 1.0,
                        'feedback': f'All {len(checks)} fields verified in row {row_idx+1} of {xlsx_file.name}/{sheet_name}.'
                    }

                result = {
                    'pass': False,
                    'score': score,
                    'feedback': (
                        f'Row {row_idx+1} of {xlsx_file.name}/{sheet_name} — {len(failed_lines)} field(s) failed (score {score:.0%}):\n'
                        + '\n'.join(failed_lines)
                    )
                }
                if best_result is None or result['score'] > best_result['score']:
                    best_result = result

    if best_result:
        return best_result
    return {'pass': False, 'score': 0.0, 'feedback': 'No readable xlsx file found in workspace'}

from pathlib import Path
import json
import re

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {'pass': False, 'score': 0.0, 'feedback': 'external_services_path is None'}

    slack_path = Path(external_services_path) / 'slack_data.json'
    if not slack_path.exists():
        return {'pass': False, 'score': 0.0, 'feedback': 'slack_data.json not found'}

    with open(slack_path) as f:
        data = json.load(f)

    channels = data.get('channels', {})
    channel_id = None
    if 'C001' in channels:
        channel_id = 'C001'
    else:
        for cid, cinfo in channels.items():
            cname = cinfo.get('name', '').lower().replace('-', '').replace('_', '').replace(' ', '')
            if 'receivinghouston' in cname:
                channel_id = cid
                break

    if channel_id is None:
        return {
            'pass': False, 'score': 0.0,
            'feedback': f'C001 / #receiving-houston not found. Available: {list(channels.keys())}'
        }

    messages = data.get('messages', {}).get(channel_id, [])
    if not messages:
        return {'pass': False, 'score': 0.0, 'feedback': f'No messages in channel {channel_id}'}

    INITIAL_LAST_TS = 1775137500.0
    messages = [m for m in messages if float(m.get('ts', 0)) > INITIAL_LAST_TS]
    if not messages:
        return {'pass': False, 'score': 0.0, 'feedback': f'No new messages in C001 (#receiving-houston) after ts {INITIAL_LAST_TS}'}

    def norm(s):
        s = str(s).lower()
        for ch in ('\u2212', '\u2013', '\u2014'):
            s = s.replace(ch, '-')
        s = re.sub(r'[^\w\s\-]', '', s)  # removes °, parens, colon, comma — keeps hyphens
        s = re.sub(r'\s+', ' ', s).strip()
        return s

    # S3 template components — all required
    CHECKS = {
        'opening phrase':       lambda t: 'variance detected' in t,
        'manifest':             lambda t: '2026-04-02-001' in t,
        'received with flags':  lambda t: 'received with flags' in t,
        'temp -9':              lambda t: '-9' in t,
        'temp tier p4':         lambda t: 'p4' in t,
        'variance -1 case':     lambda t: '-1' in t and 'case' in t,
        'email sent':           lambda t: 'email sent' in t,
        'production planner':   lambda t: 'production planner' in t,
        'dc manager':           lambda t: 'dc manager' in t
    }

    matching = []
    best_score = 0.0
    best_detail = None

    for msg in messages:
        text = msg.get('text', '')
        t = norm(text)
        results = {k: fn(t) for k, fn in CHECKS.items()}
        failed = [k for k, v in results.items() if not v]
        score = (len(CHECKS) - len(failed)) / len(CHECKS)
        if score > best_score:
            best_score = score
            best_detail = {'failed': failed, 'text': text}
        if not failed:
            matching.append(msg)

    if len(matching) == 0:
        return {
            'pass': False,
            'score': 0.0,
            'feedback': (
                f'No S3 message found in C001 (#receiving-houston). '
                f'{len(messages)} message(s) checked. '
                f'Best match (score {best_score:.0%}) — failed: {best_detail["failed"]}. '
                f'Text: "{best_detail["text"]}"'
            )
        }
    if len(matching) > 1:
        return {
            'pass': False,
            'score': 0.5,
            'feedback': (
                f'{len(matching)} matching messages found in C001; expected exactly 1. '
                f'Texts: {[m["text"][:150] for m in matching]}'
            )
        }

    return {
        'pass': True,
        'score': 1.0,
        'feedback': f'Exactly 1 S3 message verified in C001 (#receiving-houston): "{matching[0]["text"]}"'
    }

from pathlib import Path
import json
import openpyxl


def verify(workspace_path, external_services_path=None):
    failures = []
    checks_passed = 0
    total_checks = 0

    def count_xlsx_data_rows(file_path):
        wb = openpyxl.load_workbook(file_path, read_only=True, data_only=True)
        ws = wb.active
        rows = list(ws.iter_rows(min_row=1))
        wb.close()
        # All workspace xlsx files have 3 header rows (title, subtitle, column headers)
        data_rows = sum(
            1 for row in rows[3:]
            if any(cell.value is not None for cell in row)
        )
        return data_rows

    # ── 1. calendar_data.json ──────────────────────────────────────────────────
    total_checks += 1
    cal_path = Path(external_services_path) / 'calendar_data.json' if external_services_path else None
    if cal_path and cal_path.exists():
        try:
            with open(cal_path) as f:
                cal = json.load(f)
            events = cal.get('events', {})
            n = len(events)
            if n == 53:
                checks_passed += 1
            else:
                failures.append(f'calendar_data.json: {n} events (expected 53)')
        except Exception as e:
            failures.append(f'calendar_data.json: read error — {e}')
    else:
        failures.append('calendar_data.json: not found')

    # ── 2. expiry_tracker.xlsx ────────────────────────────────────────────────
    total_checks += 1
    et_path = Path(workspace_path) / 'expiry_tracker.xlsx'
    if et_path.exists():
        try:
            n = count_xlsx_data_rows(et_path)
            if n == 16:
                checks_passed += 1
            else:
                failures.append(f'expiry_tracker.xlsx: {n} data rows (expected 16)')
        except Exception as e:
            failures.append(f'expiry_tracker.xlsx: read error — {e}')
    else:
        failures.append('expiry_tracker.xlsx: not found')

    # ── 3. inventory_master.xlsx ──────────────────────────────────────────────
    total_checks += 1
    im_path = Path(workspace_path) / 'inventory_master.xlsx'
    if im_path.exists():
        try:
            n = count_xlsx_data_rows(im_path)
            if n == 16:
                checks_passed += 1
            else:
                failures.append(f'inventory_master.xlsx: {n} data rows (expected 16)')
        except Exception as e:
            failures.append(f'inventory_master.xlsx: read error — {e}')
    else:
        failures.append('inventory_master.xlsx: not found')

    # ── 4. inbound_receiving_log.xlsx ─────────────────────────────────────────
    total_checks += 1
    irl_path = Path(workspace_path) / 'inbound_receiving_log.xlsx'
    if irl_path.exists():
        try:
            n = count_xlsx_data_rows(irl_path)
            if n == 14:
                checks_passed += 1
            else:
                failures.append(f'inbound_receiving_log.xlsx: {n} data rows (expected 14)')
        except Exception as e:
            failures.append(f'inbound_receiving_log.xlsx: read error — {e}')
    else:
        failures.append('inbound_receiving_log.xlsx: not found')

    # ── 5. mailbox.json ───────────────────────────────────────────────────────
    total_checks += 1
    mail_path = Path(external_services_path) / 'mailbox.json' if external_services_path else None
    if mail_path and mail_path.exists():
        try:
            with open(mail_path) as f:
                mail = json.load(f)
            folder_counts = {}
            for em in mail.get('emails', []):
                fld = str(em.get('folder', '')).strip().lower()
                folder_counts[fld] = folder_counts.get(fld, 0) + 1

            expected = {'sent': 8, 'drafts': 0, 'receiving': 3, 'inbox': 1}
            folder_failures = [
                f'{fld}: {folder_counts.get(fld, 0)} (expected {exp})'
                for fld, exp in expected.items()
                if folder_counts.get(fld, 0) != exp
            ]
            if not folder_failures:
                checks_passed += 1
            else:
                failures.append(f'mailbox.json folder counts: {"; ".join(folder_failures)}')
        except Exception as e:
            failures.append(f'mailbox.json: read error — {e}')
    else:
        failures.append('mailbox.json: not found')

    # ── 6. slack_data.json ────────────────────────────────────────────────────
    total_checks += 1
    slack_path = Path(external_services_path) / 'slack_data.json' if external_services_path else None
    if slack_path and slack_path.exists():
        try:
            with open(slack_path) as f:
                slack = json.load(f)
            messages = slack.get('messages', {})

            expected = {
                'C001': 8, 'C002': 4, 'C003': 0, 'C004': 0, 'C005': 0,
                'C006': 1, 'D001': 1, 'D002': 0, 'D003': 0, 'D004': 0,
            }
            channel_failures = [
                f'{ch}: {len(messages.get(ch, []))} (expected {exp})'
                for ch, exp in expected.items()
                if len(messages.get(ch, [])) != exp
            ]
            if not channel_failures:
                checks_passed += 1
            else:
                failures.append(f'slack_data.json channel counts: {"; ".join(channel_failures)}')
        except Exception as e:
            failures.append(f'slack_data.json: read error — {e}')
    else:
        failures.append('slack_data.json: not found')

    # ── Result ────────────────────────────────────────────────────────────────
    score = checks_passed / total_checks if total_checks else 0.0
    if not failures:
        return {'pass': True, 'score': 1.0, 'feedback': f'All {total_checks} count checks passed.'}
    return {
        'pass': False,
        'score': score,
        'feedback': f'{len(failures)}/{total_checks} checks failed:\n' + '\n'.join(f'  {f}' for f in failures)
    }
